const crypto = require('crypto');
const body  = $input.first().json;
const ts    = body.headers?.['x-llm-timestamp'] || body.headers?.['x-request-timestamp'] || '';
const sig   = body.headers?.['x-llm-signature']  || body.headers?.['x-request-signature']  || '';
if (!ts || !sig) return [{ json:{ valid:false, reason:'Missing signature headers', body } }];
const payload = JSON.stringify(body.body || body);
const raw     = ts + '\r\nPOST\r\n/webhook/lalamove-eventos\r\n\r\n' + payload;
const expected = crypto.createHmac('sha256','sk_prod_v30Ci06vXqPeizCg6e461VZEymmFzMDAXZQwTm3NdYcwyLaS8nxrQEX0JKcp0mAM').update(raw).digest('hex');
return [{ json:{ valid: sig === expected, body: body.body || body } }];

const body      = $input.first().json.body || $input.first().json;
const eventType = body.eventType || body.event;
const orderId   = body.orderId || body.data?.orderId || '';
const driver    = body.data?.driver || body.driver || {};
// Mapeamento evento → estágio B24
const STAGE = {
  'ORDER_ACCEPTED':  'PREPARATION',
  'DRIVER_ARRIVED':  'IN_PROCESS',
  'ORDER_PICKED_UP': 'IN_PROCESS',
  'ORDER_COMPLETED': 'WON',
  'ORDER_DELIVERED': 'WON',
  'ORDER_CANCELLED': 'LOSE',
  'DRIVER_REJECTED': 'LOSE',
};
const stage_key = STAGE[eventType] || null;
return [{ json:{
  eventType, orderId, driver, stage_key,
  is_final: ['ORDER_COMPLETED','ORDER_DELIVERED','ORDER_CANCELLED','DRIVER_REJECTED'].includes(eventType),
  trigger_pod: ['ORDER_COMPLETED','ORDER_DELIVERED'].includes(eventType),
} }];

const d     = $input.first().json;
const token = $env.B24_TOKEN;
return [{ json:{
  ...d,
  _url: 'https://promobrindes.bitrix24.com.br/rest/1/'+token+'/crm.item.list?entityTypeId=1690&filter[ufCrm276_1758817942]='+d.orderId+'&select[]=id&select[]=stageId&select[]=categoryId'
} }];

const evtData = $('🗺️ Map Event').first().json;
const items   = $('🔍 Find SPA').first().json?.result?.items || [];
const token   = $env.B24_TOKEN;
if (!items.length) return [{ json:{ skipped:true, reason:'orderId '+evtData.orderId+' não encontrado', _trigger_pod:false } }];
const item     = items[0];
const stageId  = evtData.stage_key ? 'DT1690_'+item.categoryId+':'+evtData.stage_key : null;
const fields   = stageId ? {stageId} : {};
const body     = {entityTypeId:1690,id:parseInt(item.id),fields};
return [{ json:{
  spa_id:       item.id,
  orderId:      evtData.orderId,
  eventType:    evtData.eventType,
  _trigger_pod: evtData.trigger_pod,
  _url:  'https://promobrindes.bitrix24.com.br/rest/1/'+token+'/crm.item.update',
  _body: JSON.stringify(body),
} }];

const d = $input.first().json;
if (!d._trigger_pod || d.skipped) return [{ json:{ skipped:true } }];
try {
  await this.helpers.httpRequest({
    method:'POST', url:'https://webhook.atomicabr.com.br/webhook/lalamove-pod',
    body:{spa_id:d.spa_id, orderId:d.orderId},
    headers:{'Content-Type':'application/json'},
    timeout:5000, ignoreHttpStatusErrors:true,
  });
} catch(e) { /* timeout esperado — F04 responde async */ }
return [{ json:{ pod_triggered:true, spa_id:d.spa_id } }];
